import org.openqa.selenium.NoSuchElementException;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.FindBy;
import org.openqa.selenium.support.PageFactory;

public class LoginPage {

    private final WebDriver driver;

    @FindBy(id = "username")
    private WebElement usernameField;

    @FindBy(id = "password")
    private WebElement passwordField;

    @FindBy(id = "login-btn")
    private WebElement loginButton;

    @FindBy(id = "error-msg")
    private WebElement errorMessage;

    public LoginPage(WebDriver driver) {
        this.driver = driver;
        PageFactory.initElements(driver, this);
    }

    public void login(String username, String password) {
        usernameField.clear();
        usernameField.sendKeys(username);
        passwordField.clear();
        passwordField.sendKeys(password);
        loginButton.click();
    }

    public String getErrorMessage() {
        try {
            return errorMessage.isDisplayed() ? errorMessage.getText() : "";
        } catch (NoSuchElementException e) {
            return "";
        }
    }
}

import org.openqa.selenium.StaleElementReferenceException;
import org.openqa.selenium.WebElement;
import java.util.function.Consumer;
import java.util.function.Supplier;

public class RetryUtils {

    public static void retryOnStale(
            Supplier<WebElement> locator,
            Consumer<WebElement> action,
            int maxRetries) {

        StaleElementReferenceException lastException = null;

        for (int attempt = 0; attempt < maxRetries; attempt++) {
            try {
                WebElement element = locator.get();
                action.accept(element);
                return;
            } catch (StaleElementReferenceException e) {
                lastException = e;
            }
        }
        throw lastException;
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.NoSuchElementException;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import java.util.Arrays;

public class LocatorUtils {

    public static WebElement findByAny(WebDriver driver, By... locators) {
        for (By locator : locators) {
            try {
                return driver.findElement(locator);
            } catch (NoSuchElementException ignored) {
                // try next locator
            }
        }
        throw new NoSuchElementException(
                "Element not found with any of: " + Arrays.toString(locators));
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.Select;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.time.Duration;

public class DropdownUtils {

    public static String selectDropdownOption(WebDriver driver, By dropdownLocator, String visibleText) {
        WebElement dropdownElement = new WebDriverWait(driver, Duration.ofSeconds(5))
                .until(ExpectedConditions.elementToBeClickable(dropdownLocator));

        Select select = new Select(dropdownElement);
        select.selectByVisibleText(visibleText);

        return select.getFirstSelectedOption().getAttribute("value");
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.interactions.Actions;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.time.Duration;

public class MenuUtils {

    public static void hoverAndClickSubmenu(WebDriver driver, By menuItemLocator, By submenuItemLocator) {
        WebElement menuItem = new WebDriverWait(driver, Duration.ofSeconds(5))
                .until(ExpectedConditions.visibilityOfElementLocated(menuItemLocator));

        new Actions(driver)
                .moveToElement(menuItem)
                .perform();

        WebElement submenuItem = new WebDriverWait(driver, Duration.ofSeconds(5))
                .until(ExpectedConditions.visibilityOfElementLocated(submenuItemLocator));

        submenuItem.click();
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.io.File;
import java.time.Duration;

public class FileUploadUtils {

    public static boolean uploadFile(WebDriver driver,
                                     By fileInputLocator,
                                     String absoluteFilePath,
                                     By fileNameDisplayLocator) {
        String fileName = new File(absoluteFilePath).getName();

        driver.findElement(fileInputLocator).sendKeys(absoluteFilePath);

        try {
            new WebDriverWait(driver, Duration.ofSeconds(5))
                    .until(ExpectedConditions.textToBePresentInElementLocated(
                            fileNameDisplayLocator, fileName));
            return true;
        } catch (org.openqa.selenium.TimeoutException e) {
            return false;
        }
    }
}

import org.openqa.selenium.Cookie;
import org.openqa.selenium.WebDriver;

public class CookieUtils {

    public static void addAuthCookie(WebDriver driver, String name, String value, String domain) {
        Cookie authCookie = new Cookie.Builder(name, value)
                .domain(domain)
                .path("/")
                .isSecure(true)
                .build();
        driver.manage().addCookie(authCookie);
    }

    public static String getCookieValue(WebDriver driver, String name) {
        Cookie cookie = driver.manage().getCookieNamed(name);
        return cookie != null ? cookie.getValue() : null;
    }

    public static void clearAllCookies(WebDriver driver) {
        driver.manage().deleteAllCookies();
        driver.navigate().refresh();
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.chrome.ChromeDriver;
import org.openqa.selenium.devtools.DevTools;
import org.openqa.selenium.devtools.v129.network.Network;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.TimeUnit;

public class CdpNetworkUtils {

    public static List<String> captureApiRequests(
            ChromeDriver driver,
            String urlPattern,
            Runnable triggerAction) throws InterruptedException {

        DevTools devTools = driver.getDevTools();
        devTools.createSession();
        devTools.send(Network.enable(
                Optional.empty(), Optional.empty(), Optional.empty()));

        List<String> matchedUrls = new CopyOnWriteArrayList<>();

        devTools.addListener(Network.requestWillBeSent(), request -> {
            String url = request.getRequest().getUrl();
            if (url.contains(urlPattern)) {
                matchedUrls.add(url);
            }
        });

        triggerAction.run();

        long deadline = System.currentTimeMillis() + 5000;
        while (matchedUrls.isEmpty() && System.currentTimeMillis() < deadline) {
            TimeUnit.MILLISECONDS.sleep(200);
        }

        devTools.send(Network.disable());
        return matchedUrls;
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.ExpectedCondition;
import org.openqa.selenium.support.ui.WebDriverWait;
import java.time.Duration;

public class CustomWaitUtils {

    public static void waitForAttributeContains(
            WebDriver driver,
            By locator,
            String attribute,
            String expectedValue,
            int timeoutSeconds) {

        ExpectedCondition<Boolean> attributeContains = d -> {
            try {
                WebElement element = d.findElement(locator);
                String attrValue = element.getAttribute(attribute);
                return attrValue != null && attrValue.contains(expectedValue);
            } catch (org.openqa.selenium.NoSuchElementException e) {
                return false;
            }
        };

        new WebDriverWait(driver, Duration.ofSeconds(timeoutSeconds))
                .until(attributeContains);
    }
}

import org.openqa.selenium.WebDriver;
import org.openqa.selenium.chrome.ChromeOptions;
import org.openqa.selenium.remote.RemoteWebDriver;
import java.net.MalformedURLException;
import java.net.URL;
import java.time.Duration;

public class DriverFactory {

    public static WebDriver createRemoteDriver(String gridUrl, boolean headless)
            throws MalformedURLException {

        ChromeOptions options = new ChromeOptions();
        options.addArguments("--no-sandbox");
        options.addArguments("--disable-dev-shm-usage");
        options.addArguments("--window-size=1920,1080");

        if (headless) {
            options.addArguments("--headless=new");
        }

        WebDriver driver = new RemoteWebDriver(new URL(gridUrl), options);
        driver.manage().timeouts().implicitlyWait(Duration.ofSeconds(0));

        return driver;
    }
}

import org.openqa.selenium.By;
import org.openqa.selenium.SearchContext;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;

public class ShadowDomUtils {

    public static String fillShadowInput(
            WebDriver driver,
            By shadowHostLocator,
            String cssInsideShadow,
            String value) {

        WebElement shadowHost = driver.findElement(shadowHostLocator);
        SearchContext shadowRoot = shadowHost.getShadowRoot();

        WebElement input = shadowRoot.findElement(By.cssSelector(cssInsideShadow));
        input.clear();
        input.sendKeys(value);

        return input.getAttribute("value");
    }
}

